class Solution:
    def smallestEquivalentString(self, s1: str, s2: str, baseStr: str) -> str:
        parent = {}
        for c1, c2 in zip(s1, s2):
            root1 = self.find(parent, c1)
            root2 = self.find(parent, c2)
            if root1 != root2:
                parent[root1] = root2
        for c in baseStr:
            root = self.find(parent, c)
            print(root)
            baseStr = baseStr.replace(c, chr(ord('a') + root - 1), 1)
        return baseStr

    def find(self, parent, c):
        if c not in parent:
            parent[c] = c
        if parent[c] != c:
            parent[c] = self.find(parent, parent[c])
        return parent[c]
